"use strict";module.exports={meta:{type:"suggestion",docs:{description:"Disallow lexical declarations in case clauses",recommended:!0,url:"https://eslint.org/docs/latest/rules/no-case-declarations"},hasSuggestions:!0,schema:[],messages:{addBrackets:"Add {} brackets around the case block.",unexpected:"Unexpected lexical declaration in case block."}},create(e){function t(e){switch(e.type){case"FunctionDeclaration":case"ClassDeclaration":return!0;case"VariableDeclaration":return"var"!==e.kind;default:return!1}}return{SwitchCase(s){for(let a=0;a<s.consequent.length;a++){const c=s.consequent[a];t(c)&&e.report({node:c,messageId:"unexpected",suggest:[{messageId:"addBrackets",fix:e=>[e.insertTextBefore(s.consequent[0],"{ "),e.insertTextAfter(s.consequent.at(-1)," }")]}]})}}}}};